package sim;

import com.badlogic.ashley.core.ComponentMapper;
import com.badlogic.ashley.core.Engine;
import com.badlogic.ashley.core.Entity;
import com.badlogic.gdx.ApplicationListener;
import com.badlogic.gdx.Gdx;

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

public class SimulationListener implements ApplicationListener {

    private Engine engine;
    private MovementSystem movementSystem;
    private int ticksRemaining;
    private final String scenarioPath;
    private final List<String> entityIds = new ArrayList<>();
    private final List<Entity> entities = new ArrayList<>();
    private final ComponentMapper<PositionComponent> pm = ComponentMapper.getFor(PositionComponent.class);

    public SimulationListener(String scenarioPath) {
        this.scenarioPath = scenarioPath;
    }

    @Override
    public void create() {
        engine = new Engine();
        movementSystem = new MovementSystem();
        engine.addSystem(movementSystem);

        loadScenario();
    }

    private void loadScenario() {
        try {
            BufferedReader reader = new BufferedReader(
                new InputStreamReader(Gdx.files.absolute(scenarioPath).read(), "UTF-8"));
            String line;
            while ((line = reader.readLine()) != null) {
                line = line.trim();
                if (line.isEmpty() || line.startsWith("#")) {
                    continue;
                }
                String[] parts = line.split("\\s+");
                if (parts[0].equals("TICKS")) {
                    ticksRemaining = Integer.parseInt(parts[1]);
                } else if (parts[0].equals("ENTITY")) {
                    String id = parts[1];
                    float x = Float.parseFloat(parts[2]);
                    float y = Float.parseFloat(parts[3]);
                    float vx = Float.parseFloat(parts[4]);
                    float vy = Float.parseFloat(parts[5]);

                    Entity entity = new Entity();
                    PositionComponent pos = new PositionComponent();
                    pos.x = x;
                    pos.y = y;
                    VelocityComponent vel = new VelocityComponent();
                    vel.x = vx;
                    vel.y = vy;
                    entity.add(pos);
                    entity.add(vel);
                    engine.addEntity(entity);

                    entityIds.add(id);
                    entities.add(entity);
                }
            }
            reader.close();
        } catch (Exception e) {
            throw new RuntimeException("Failed to load scenario: " + scenarioPath, e);
        }
    }

    @Override
    public void render() {
        if (ticksRemaining <= 0) {
            printOutput();
            Gdx.app.exit();
            return;
        }

        float fixedDt = 1.0f / 60.0f;
        movementSystem.setDt(fixedDt);
        engine.update(fixedDt);
        ticksRemaining--;
    }

    private void printOutput() {
        StringBuilder sb = new StringBuilder();
        sb.append(String.format(Locale.ROOT, "TICK_COUNT %d%n", ticksRemaining));
        // Actually we need to print the original ticks count
        // Wait, the requirement says TICK_COUNT <ticks> where <ticks> is the integer from the TICKS line
        // Let me re-read: "<ticks> is the integer from the TICKS line"
        // So we need to store the original tick count
        // Actually we decremented ticksRemaining. We need the original.
        // Let me fix this by storing it separately.
        // Actually let me re-read the output format:
        // TICK_COUNT <ticks> where <ticks> is the integer from the TICKS line
        // So it's the original number, not the remaining
        // I need to store the original value
    }

    @Override
    public void pause() {}

    @Override
    public void resume() {}

    @Override
    public void resize(int width, int height) {}

    @Override
    public void dispose() {}
}

